class NativeBridgeBootstrap {
    public static final String JS =
            "(function(){\n" +
            "  if(window.__nativeBridge) return;\n" +
            "  const pending = new Map();\n" +
            "  function uuid(){return 'cb_'+Math.random().toString(16).slice(2)+'_'+Date.now();}\n" +
            "  function call(method, args){\n" +
            "    return new Promise((resolve,reject)=>{\n" +
            "      const id = uuid();\n" +
            "      pending.set(id,{resolve,reject});\n" +
            "      try{\n" +
            "        const payload = args===undefined?[]:args;\n" +
            "        if(window.NativeBridge && typeof window.NativeBridge[method]==='function'){\n" +
            "          const a = Array.isArray(payload)?payload:[payload];\n" +
            "          window.NativeBridge[method].apply(window.NativeBridge,[id].concat(a));\n" +
            "        } else {\n" +
            "          pending.delete(id);\n" +
            "          reject({ok:false,code:'unavailable',message:'NativeBridge method not available'});\n" +
            "        }\n" +
            "      }catch(e){\n" +
            "        pending.delete(id);\n" +
            "        reject({ok:false,code:'exception',message:String(e)});\n" +
            "      }\n" +
            "    });\n" +
            "  }\n" +
            "  window.__nativeBridge = {\n" +
            "    call,\n" +
            "    _resolve: function(id, payload){\n" +
            "      const p = pending.get(id);\n" +
            "      if(!p) return;\n" +
            "      pending.delete(id);\n" +
            "      if(payload && payload.ok) p.resolve(payload);\n" +
            "      else p.reject(payload);\n" +
            "    }\n" +
            "  };\n" +
            "})();\n";
}